sys_script_client.script:
function onSubmit() {

    var requestType = g_form.getDisplayBox('request_type').value;
    var requiredByDate = g_form.getValue('required_by_date');

    if (requestType == 'Static IP Allocation' && requiredByDate == '') {

        g_form.addErrorMessage(
            'Required By Date is mandatory for Static IP Allocation requests.'
        );

        return false;
    }

    if (requiredByDate != '') {

        var today = new Date();
        today.setHours(0, 0, 0, 0);

        var requiredDate = new Date(requiredByDate);

        if (requiredDate < today) {

            g_form.addErrorMessage(
                'Required By Date cannot be earlier than today.'
            );

            return false;
        }

    }

    return true;

}
